import { Delaunay } from 'https://cdn.jsdelivr.net/npm/d3-delaunay@6.0.4/+esm';
const delaunay = Delaunay.from(data.points); // [[x,y],...]
const bounds = data.bounds ?? [0, 0, 960, 500];
const voronoi = delaunay.voronoi(bounds);
